import React, { useState, useEffect, useContext } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { FaHeart, FaRegHeart, FaBookmark, FaRegBookmark, FaShare, FaArrowLeft, FaTrash } from 'react-icons/fa';
import { toast } from 'react-toastify';
import { AuthContext } from '../context/AuthContext';
import forumService from '../services/forumService';
import Spinner from '../components/Spinner';
import formatDate from '../utils/formatDate';

const PostDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useContext(AuthContext);
  
  const [post, setPost] = useState(null);
  const [comments, setComments] = useState([]);
  const [isLiked, setIsLiked] = useState(false);
  const [likeCount, setLikeCount] = useState(0);
  const [isBookmarked, setIsBookmarked] = useState(false);
  const [loading, setLoading] = useState(true);
  const [commentText, setCommentText] = useState('');
  const [submittingComment, setSubmittingComment] = useState(false);
  const [deleteConfirm, setDeleteConfirm] = useState(false);

  useEffect(() => {
    const fetchPostDetails = async () => {
      try {
        setLoading(true);
        const data = await forumService.getPostById(id);
        setPost(data);
        setComments(data.comments || []);
        setLikeCount(data.likes?.length || 0);
        setIsLiked(user && data.likes?.includes(user._id));
        setIsBookmarked(data.isBookmarked);
      } catch (error) {
        console.error('Error fetching post:', error);
        toast.error('Failed to load post details');
        navigate('/forum');
      } finally {
        setLoading(false);
      }
    };

    fetchPostDetails();
  }, [id, user, navigate]);

  const handleLike = async () => {
    if (!user) {
      toast.error('Please login to like posts');
      return;
    }

    try {
      await forumService.likePost(id);
      const newLikedState = !isLiked;
      setIsLiked(newLikedState);
      setLikeCount(prevCount => newLikedState ? prevCount + 1 : prevCount - 1);
    } catch (error) {
      console.error('Error liking post:', error);
      toast.error('Failed to like post');
    }
  };

  const handleBookmark = async () => {
    if (!user) {
      toast.error('Please login to bookmark posts');
      return;
    }

    try {
      await forumService.bookmarkPost(id);
      setIsBookmarked(!isBookmarked);
      toast.success(isBookmarked ? 'Post removed from bookmarks' : 'Post added to bookmarks');
    } catch (error) {
      console.error('Error bookmarking post:', error);
      toast.error('Failed to bookmark post');
    }
  };

  const handleShare = () => {
    const url = `${window.location.origin}/forum/${id}`;
    
    if (navigator.share) {
      navigator.share({
        title: post.title,
        text: 'Check out this post on AgriConnect',
        url,
      })
      .catch(error => {
        console.error('Error sharing:', error);
        fallbackShare(url);
      });
    } else {
      fallbackShare(url);
    }
  };

  const fallbackShare = (url) => {
    navigator.clipboard.writeText(url)
      .then(() => toast.success('Link copied to clipboard!'))
      .catch(() => toast.error('Failed to copy link'));
  };

  const handleCommentSubmit = async (e) => {
    e.preventDefault();
    
    if (!commentText.trim()) {
      toast.error('Comment cannot be empty');
      return;
    }
    
    if (!user) {
      toast.error('Please login to comment');
      return;
    }
    
    try {
      setSubmittingComment(true);
      const response = await forumService.addComment(id, { content: commentText });
      setComments([...comments, response]);
      setCommentText('');
      toast.success('Comment added successfully');
    } catch (error) {
      console.error('Error adding comment:', error);
      toast.error('Failed to add comment');
    } finally {
      setSubmittingComment(false);
    }
  };

  const handleDeleteComment = async (commentId) => {
    try {
      await forumService.deleteComment(id, commentId);
      setComments(comments.filter(comment => comment._id !== commentId));
      toast.success('Comment deleted successfully');
    } catch (error) {
      console.error('Error deleting comment:', error);
      toast.error('Failed to delete comment');
    }
  };

  const handleDeletePost = async () => {
    if (!user || (user._id !== post.author._id && !user.isAdmin)) {
      toast.error('You do not have permission to delete this post');
      return;
    }

    try {
      await forumService.deletePost(id);
      toast.success('Post deleted successfully');
      navigate('/forum');
    } catch (error) {
      console.error('Error deleting post:', error);
      toast.error('Failed to delete post');
    }
  };

  if (loading) {
    return <Spinner />;
  }

  if (!post) {
    return (
      <div className="text-center p-8">
        <h2 className="text-2xl font-bold text-gray-800 mb-4">Post not found</h2>
        <Link to="/forum" className="text-green-600 hover:text-green-700">
          Back to Forum
        </Link>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto p-4 bg-white rounded-lg shadow-md">
      {/* Back button and actions */}
      <div className="flex justify-between items-center mb-6">
        <button 
          onClick={() => navigate('/forum')} 
          className="flex items-center text-gray-600 hover:text-gray-800"
        >
          <FaArrowLeft className="mr-2" />
          Back to Forum
        </button>
        
        <div className="flex space-x-4">
          <button 
            onClick={handleLike} 
            className={`flex items-center ${isLiked ? 'text-red-500' : 'text-gray-500'} hover:text-red-500`}
          >
            {isLiked ? <FaHeart size={20} /> : <FaRegHeart size={20} />}
            <span className="ml-1">{likeCount}</span>
          </button>
          
          <button 
            onClick={handleBookmark} 
            className={`${isBookmarked ? 'text-blue-500' : 'text-gray-500'} hover:text-blue-500`}
          >
            {isBookmarked ? <FaBookmark size={20} /> : <FaRegBookmark size={20} />}
          </button>
          
          <button 
            onClick={handleShare} 
            className="text-gray-500 hover:text-green-500"
          >
            <FaShare size={20} />
          </button>
          
          {user && (user._id === post.author._id || user.isAdmin) && (
            <>
              {!deleteConfirm ? (
                <button 
                  onClick={() => setDeleteConfirm(true)} 
                  className="text-gray-500 hover:text-red-500"
                >
                  <FaTrash size={20} />
                </button>
              ) : (
                <div className="flex items-center">
                  <span className="text-sm text-red-500 mr-2">Confirm delete?</span>
                  <button 
                    onClick={handleDeletePost} 
                    className="text-white bg-red-500 hover:bg-red-600 px-2 py-1 rounded text-sm mr-1"
                  >
                    Yes
                  </button>
                  <button 
                    onClick={() => setDeleteConfirm(false)} 
                    className="text-white bg-gray-500 hover:bg-gray-600 px-2 py-1 rounded text-sm"
                  >
                    No
                  </button>
                </div>
              )}
            </>
          )}
        </div>
      </div>
      
      {/* Post content */}
      <div className="mb-8">
        <div className="flex items-center mb-4">
          <img 
            src={post.author?.profilePicture || 'https://via.placeholder.com/40'} 
            alt={post.author?.name} 
            className="w-12 h-12 rounded-full mr-4"
          />
          <div>
            <h3 className="font-semibold text-lg">{post.author?.name || 'Anonymous'}</h3>
            <p className="text-sm text-gray-500">{formatDate(post.createdAt)}</p>
            {post.category && (
              <span className="inline-block bg-green-100 text-green-800 text-xs px-2 py-1 rounded-full mt-1">
                {post.category}
              </span>
            )}
          </div>
        </div>
        
        <h1 className="text-3xl font-bold text-gray-900 mb-4">{post.title}</h1>
        
        <div className="prose max-w-none mb-6">
          <p className="text-gray-700 whitespace-pre-line">{post.content}</p>
        </div>
        
        {post.image && (
          <div className="mb-6">
            <img 
              src={post.image} 
              alt={post.title} 
              className="w-full max-h-96 object-contain rounded-lg"
            />
          </div>
        )}
      </div>
      
      {/* Comments section */}
      <div className="border-t pt-6">
        <h2 className="text-xl font-semibold mb-6">
          Comments ({comments.length})
        </h2>
        
        {/* Comment form */}
        {user ? (
          <form onSubmit={handleCommentSubmit} className="mb-8">
            <div className="flex">
              <img 
                src={user.profilePicture || 'https://via.placeholder.com/40'} 
                alt={user.name} 
                className="w-10 h-10 rounded-full mr-3"
              />
              <div className="flex-grow">
                <textarea
                  className="w-full px-3 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-green-500"
                  rows="3"
                  placeholder="Add a comment..."
                  value={commentText}
                  onChange={(e) => setCommentText(e.target.value)}
                  required
                ></textarea>
                <div className="mt-2 text-right">
                  <button 
                    type="submit" 
                    className="bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition duration-200"
                    disabled={submittingComment}
                  >
                    {submittingComment ? 'Posting...' : 'Post Comment'}
                  </button>
                </div>
              </div>
            </div>
          </form>
        ) : (
          <div className="bg-gray-50 p-4 rounded-lg mb-6 text-center">
            <p className="text-gray-600">
              Please <Link to="/login" className="text-green-600 font-medium">log in</Link> to add a comment.
            </p>
          </div>
        )}
        
        {/* Comments list */}
        <div className="space-y-6">
          {comments.length > 0 ? (
            comments.map((comment) => (
              <div key={comment._id} className="flex border-b pb-4 last:border-0">
                <img 
                  src={comment.author?.profilePicture || 'https://via.placeholder.com/40'} 
                  alt={comment.author?.name} 
                  className="w-10 h-10 rounded-full mr-3"
                />
                <div className="flex-grow">
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className="font-medium text-gray-900">
                        {comment.author?.name || 'Anonymous'}
                      </h4>
                      <p className="text-xs text-gray-500">{formatDate(comment.createdAt)}</p>
                    </div>
                    {user && (user._id === comment.author?._id || user.isAdmin) && (
                      <button
                        onClick={() => handleDeleteComment(comment._id)}
                        className="text-gray-400 hover:text-red-500"
                      >
                        <FaTrash size={14} />
                      </button>
                    )}
                  </div>
                  <p className="mt-2 text-gray-700">{comment.content}</p>
                </div>
              </div>
            ))
          ) : (
            <p className="text-gray-500 text-center italic">No comments yet. Be the first to comment!</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default PostDetail;
